+    if (match(Src, m_Shr(m_APInt(ShrC), m_Value(X)))) {
+      // trunc (shr C, X) to i1 --> icmp eq X, log2(C), where C is power of 2
+      if (ShrC->isPowerOf2()) {
+        Constant *Log2C = ConstantInt::get(SrcTy, ShrC->exactLogBase2());
+        return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C);
+      }
+      // trunc (shr C, X) to i1 --> icmp ult X, log2(C+1), where C+1 is power of 2
+      APInt CPlus1 = *ShrC + 1;
+      if (CPlus1.isPowerOf2()) {
+        Constant *Log2CPlus1 = ConstantInt::get(SrcTy, CPlus1.exactLogBase2());
+        return new ICmpInst(ICmpInst::ICMP_ULT, X, Log2CPlus1);
+      }
+    }
+
